+/**
+ * TypeScript configuration types for ReasoningBank
+ */
+
+export interface ReasoningBankConfig {
+  retrieve: {
+    k: number;
+    alpha: number;
+    beta: number;
+    gamma: number;
+    delta: number;
+    recency_half_life_days: number;
+    min_score: number;
+  };
+  judge: {
+    model: string;
+    max_tokens: number;
+    confidence_threshold: number;
+  };
+  distill: {
+    model: string;
+    max_tokens: number;
+    temperature: number;
+  };
+  consolidate: {
+    duplicate_threshold: number;
+    contradiction_threshold: number;
+    trigger_threshold: number;
+    prune_age_days: number;
+    prune_min_confidence: number;
+    min_confidence_keep: number;
+  };
+  matts: {
+    parallel_k: number;
+    sequential_k: number;
+    sequential_r: number;
+    sequential_stop_on_success: boolean;
+    confidence_boost: number;
+  };
