+async function traditionalApproach(attemptNumber: number): Promise<{
+  success: boolean;
+  steps: number;
+  duration: number;
+  errors: string[];
+}> {
+  console.log(`\n📝 Traditional Approach - Attempt ${attemptNumber}`);
