+ *
+ * Usage: tsx hooks/pre-task.ts --task-id <id> --query <query> [--domain <domain>] [--agent <agent>]
+ */
+
+import { retrieveMemories, formatMemoriesForPrompt } from '../core/retrieve.js';
+import { loadConfig } from '../utils/config.js';
