+    console.log(formattedMemories);
+    console.log('=== END MEMORIES ===\n');
+
+    process.exit(0);
+  } catch (error) {
+    console.error('[PRE-TASK ERROR]', error);
+    process.exit(1);
+  }
+}
+
+main();

