+
+const __filename = fileURLToPath(import.meta.url);
+const __dirname = dirname(__filename);
+
+export async function handleReasoningBankCommand(subcommand: string): Promise<void> {
+  const args = process.argv.slice(4); // Get args after 'reasoningbank <subcommand>'
+
+  try {
+    switch (subcommand) {
+      case 'demo':
+        await runExternalScript('../reasoningbank/demo-comparison.js');
+        break;
+
+      case 'test':
+        await runExternalScript('../reasoningbank/test-validation.js');
+        break;
+
+      case 'init':
+        await initDatabase();
+        break;
+
+      case 'benchmark':
+        await runExternalScript('../reasoningbank/benchmark.js');
+        break;
+
+      case 'status':
+        await showStatus();
+        break;
+
+      case 'consolidate':
+        await runConsolidation();
+        break;
+
+      case 'list':
+        await listMemories(args);
+        break;
+
+      case 'help':
+      default:
+        printHelp();
+        break;
+    }
+  } catch (error) {
+    console.error(`\n❌ Error: ${error instanceof Error ? error.message : String(error)}\n`);
+    process.exit(1);
+  }
+}
+
+async function runExternalScript(relativePath: string): Promise<void> {
+  const scriptPath = join(__dirname, relativePath);
+
+  return new Promise((resolve, reject) => {
+    const child = spawn('node', [scriptPath], {
+      stdio: 'inherit',
+      cwd: process.cwd()
+    });
+
+    child.on('exit', (code) => {
+      if (code === 0) {
+        resolve();
+      } else {
+        reject(new Error(`Script exited with code ${code}`));
+      }
+    });
+
+    child.on('error', (error) => {
+      reject(error);
+    });
+  });
+}
