+ * - DISTILL: Extracts learnings
+ * - CONSOLIDATE: Deduplicates and prunes
+ */
+import Anthropic from '@anthropic-ai/sdk';
+import { retrieveMemories, formatMemoriesForPrompt, judgeTrajectory, distillMemories, shouldConsolidate, consolidate, db } from '../../agentic-flow/src/reasoningbank/index.js';
+import { ulid } from 'ulid';
+export class ReasoningBankAgent {
+    type = 'reasoningbank';
+    client;
+    model;
